using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using verii_metivon_api.Core.Auth;using verii_metivon_api.Modules.Pricing.Application.Parameters;
namespace verii_metivon_api.Modules.Pricing.Api;[ApiController,Authorize,Route("api/parameters/pricing")]public sealed class PricingParametersController(IPricingParameterService service):ControllerBase{[HttpGet]public async Task<IActionResult>Get([FromQuery]long?branchId,CancellationToken ct)=>Ok(ApiResponse<PricingParametersDto>.Ok(await service.GetAsync(branchId,ct)));[HttpPut,Authorize(Roles="Admin")]public async Task<IActionResult>Save(SavePricingParametersRequest r,CancellationToken ct){try{return Ok(ApiResponse<PricingParametersDto>.Ok(await service.SaveAsync(r,ct)));}catch(ArgumentException e){return BadRequest(ApiResponse<object>.Error(e.Message,400));}}}
